using System; using System.Linq; using System.Data.Entity; using System.Windows; using System.Windows.Controls; using WarehouseManagement.ApplicationData;
namespace WarehouseManagement.Pages { public partial class StockBalancesPage:Page { public StockBalancesPage(){InitializeComponent(); Load();} void Load(){lvStockBalances.ItemsSource=AppConnect.model01.StockBalances.Include("Products").Include("StorageLocations.StorageZones.Warehouses").ToList().Select(x=>new{ProductName=x.Products.ProductName,Quantity=x.Quantity,PriceAtMoment=x.Products.SalePrice,TotalPrice=x.Quantity*x.Products.SalePrice}); tbTotal.Text="Текущие остатки по местам хранения";} private void btnBack_Click(object s,RoutedEventArgs e){AppFrame.frmMain.GoBack();} private void btnUnused_Click(object s,RoutedEventArgs e){} private void btnOpenShipments_Click(object s,RoutedEventArgs e){AppFrame.frmMain.Navigate(new ShipmentsPage());}}}
